const rows = $input.all().map(i => i.json);
const now = new Date();
const today = now.toISOString().split('T')[0];

if (rows.length === 0) {
  return [{ json: { report_date: today, total_rows: 0, summary: 'No data found in sheet.' } }];
}

// Auto-detect numeric columns for aggregation
const columns = Object.keys(rows[0]);
const numericCols = [];
const textCols = [];

for (const col of columns) {
  const sample = rows.slice(0, 10).map(r => r[col]).filter(v => v !== '' && v !== null && v !== undefined);
  const isNumeric = sample.length > 0 && sample.every(v => !isNaN(parseFloat(v)));
  if (isNumeric) {
    numericCols.push(col);
  } else {
    textCols.push(col);
  }
}

// Calculate stats for numeric columns
const stats = {};
for (const col of numericCols) {
  const values = rows.map(r => parseFloat(r[col])).filter(v => !isNaN(v));
  if (values.length === 0) continue;
  stats[col] = {
    count: values.length,
    sum: Math.round(values.reduce((a, b) => a + b, 0) * 100) / 100,
    avg: Math.round((values.reduce((a, b) => a + b, 0) / values.length) * 100) / 100,
    min: Math.min(...values),
    max: Math.max(...values)
  };
}

// Build summary HTML table
let summaryHtml = '<table border="1" cellpadding="8" cellspacing="0"><tr><th>Column</th><th>Count</th><th>Sum</th><th>Average</th><th>Min</th><th>Max</th></tr>';
for (const [col, s] of Object.entries(stats)) {
  summaryHtml += `<tr><td><strong>${col}</strong></td><td>${s.count}</td><td>${s.sum}</td><td>${s.avg}</td><td>${s.min}</td><td>${s.max}</td></tr>`;
}
summaryHtml += '</table>';

// Count unique values for first text column
let categorySummary = '';
if (textCols.length > 0) {
  const firstTextCol = textCols[0];
  const valueCounts = {};
  for (const r of rows) {
    const v = (r[firstTextCol] || 'empty').toString();
    valueCounts[v] = (valueCounts[v] || 0) + 1;
  }
  categorySummary = Object.entries(valueCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([v, c]) => `${v}: ${c}`)
    .join(', ');
}

return [{
  json: {
    report_date: today,
    total_rows: rows.length,
    numeric_columns: numericCols.length,
    summary_html: summaryHtml,
    category_summary: categorySummary,
    category_column: textCols[0] || 'N/A'
  }
}];
